const body = $json.body && typeof $json.body === 'object' ? $json.body : $json;
const allowedTypes = ['drivers-license','state-id','passport','passport-card','permanent-resident-card','employment-authorization-card','military-id','unknown'];
const allowedSides = ['front','back'];
const missing = [];
for (const path of ['requestId','selectedDocumentType','documentSide','imageBase64','profile.legalFirstName','profile.legalLastName','profile.dateOfBirth']) {
  const value = path.split('.').reduce((acc, key) => acc && acc[key], body);
  if (value === undefined || value === null || value === '') missing.push(path);
}
const invalid = [];
if (body.selectedDocumentType && !allowedTypes.includes(body.selectedDocumentType)) invalid.push('selectedDocumentType');
if (body.documentSide && !allowedSides.includes(body.documentSide)) invalid.push('documentSide');
if (missing.length || invalid.length) {
  return [{ json: { valid: false, response: { success: false, requestId: body.requestId || null, error: { code: 'INVALID_REQUEST', message: 'Missing or invalid fields.', missing, invalid }, analysis: null } } }];
}
return [{ json: { ...body, valid: true } }];

const input = $json;
const raw = String(input.imageBase64 || '');
const match = raw.match(/^data:(.*?);base64,(.*)$/);
const mimeType = match ? (match[1] || 'image/png') : 'image/png';
const base64 = match ? match[2] : raw;
const extByMime = { 'image/jpeg': 'jpg', 'image/jpg': 'jpg', 'image/png': 'png', 'image/webp': 'webp' };
const extension = extByMime[mimeType] || 'png';
const fileName = `${input.requestId}-${input.selectedDocumentType}-${input.documentSide}.${extension}`;
const buffer = Buffer.from(base64, 'base64');
if (!buffer.length) throw new Error('imageBase64 decoded to an empty file');
const binary = await this.helpers.prepareBinaryData(buffer, fileName, mimeType);
return [{ json: { ...input, mimeType, fileName }, binary: { data: binary } }];

// Get data from previous nodes
const convertNode = $('Convert Base64 To Binary').item;
const uploadNode = $json;

const d = convertNode.json;
const p = d.profile || {};
const isBackSide = d.documentSide === 'back';
const isPRC = d.selectedDocumentType === 'permanent-resident-card';

// Extract binary data properly using n8n helper
const bin = convertNode.binary && convertNode.binary.data;
if (!bin) throw new Error('No binary data found from Convert Base64 To Binary node');

const buffer = await this.helpers.getBinaryDataBuffer(convertNode, 'data');
const base64Image = buffer.toString('base64');
const mimeType = bin.mimeType || d.mimeType || 'image/png';

// Known A-Number from profile if previously captured
const knownANumber = (p.aNumber || p.alienNumber || p.documentNumber || '').trim();

// Build the appropriate Gemini prompt based on which side is being submitted
let prompt;

if (isBackSide) {
  // BACK SIDE: Only verify it is the genuine back of the selected document.
  // Do NOT check name, DOB, expiry, or address — those were verified on the front.
  const prcBackExtra = isPRC
    ? `\n\nPermanent Resident Card back-side specifics:\n- The back must show USCIS security features, a 2D barcode, machine-readable zone (MRZ starting with <<), and/or fingerprint area.\n- Extract the A-Number (Alien Registration Number) from the back if visible. Format: A followed by 9 digits, e.g. A123456789.${knownANumber ? `\n- Known A-Number from profile: "${knownANumber}". If the back shows a different A-Number, set DOCUMENT_NUMBER_MISMATCH flag and canContinue=false.` : ''}`
    : '';

  prompt = `You are an identity-document verification assistant.
The user has submitted the BACK SIDE of a US government ID.
Your ONLY job is to confirm this is the correct back side of the selected document type.
Do NOT check name, date of birth, expiration date, or address — those are verified on the front.
Return strict JSON only. No Markdown, no prose.

Selected document type: ${d.selectedDocumentType}
Document side submitted: back
requestId: ${d.requestId}${prcBackExtra}

Back-side recognition rules:
- drivers-license back: Shows barcode (PDF417), magnetic stripe, state seal, vehicle restrictions, or endorsements. Usually no photo.
- state-id back: Same as driver's license back.
- passport-card back: Shows WHTI-compliant barcode, RFID chip symbol, "UNITED STATES OF AMERICA" text, eagle seal. No photo on back.
- passport (booklet) back: Blank page or decorative imagery. No personal data.
- permanent-resident-card (Green Card) back: Shows 2D barcode, MRZ lines (starting with <<), USCIS logo, fingerprint or security pattern.
- employment-authorization-card back: Shows barcode, USCIS logo, fingerprint or security pattern.
- military-id back: Shows barcode, DoD logo, or sponsor information.

If the image shows the FRONT of a document instead of the back, set detectedSide="front", sideMatchesSelection=false, flag SIDE_MISMATCH, nextAction=REQUEST_BACK_IMAGE, canContinue=false.
If the document type clearly does not match the selected type, set documentTypeMatch=false, flag DOCUMENT_TYPE_MISMATCH, canContinue=false.
If image quality is too poor to determine anything, set imageQualityLow=true, flag PHOTO_BLURRED, nextAction=RETAKE_PHOTO, canContinue=false.
Otherwise set canContinue=true, nextAction=CONTINUE.

Return exactly this JSON:
{
  "requestId": "${d.requestId}",
  "documentDetected": true,
  "userSelectedType": "${d.selectedDocumentType}",
  "userSelectedTypeLabel": "",
  "detectedDocumentType": "",
  "detectedDocumentTypeLabel": "",
  "documentTypeMatch": true,
  "detectedSide": "back",
  "sideMatchesSelected": true,
  "extractedFields": {
    "first_name": null, "middle_name": null, "last_name": null, "full_name_raw": null,
    "date_of_birth": null, "expiration_date": null, "issue_date": null, "document_number": null,
    "address_line1": null, "city": null, "state": null, "zip": null, "sex": null,
    "card_number": null, "a_number": null, "category": null, "country_of_birth": null
  },
  "validationResults": {
    "nameMatch": { "status": "NOT_CHECKED", "details": "Back side — name not checked", "userProvided": null, "documentExtracted": null },
    "dobMatch": { "status": "NOT_CHECKED", "details": "Back side — DOB not checked", "userProvided": null, "documentExtracted": null },
    "addressMatch": { "status": "NOT_CHECKED", "details": null, "userProvided": null, "documentExtracted": null },
    "expirationStatus": "NOT_CHECKED",
    "photoIntegrity": "CLEAR"
  },
  "booleanChecks": {
    "documentDetected": true, "supportedDocumentType": true, "documentTypeMatchesSelection": true,
    "sideMatchesSelection": true, "frontImageRequired": false, "backImageRequired": false,
    "nameExtracted": false, "dobExtracted": false, "nameMatchesProfile": true, "dobMatchesProfile": true,
    "addressMatchesProfile": true, "documentExpired": false, "documentExpiresSoon": false,
    "imageQualityLow": false, "glareDetected": false, "croppedDocument": false,
    "physicalDocumentLikely": true, "digitalManipulationSuspected": false,
    "humanReviewRequired": false, "canContinue": true
  },
  "flags": [],
  "complianceEligibility": true,
  "nextAction": "CONTINUE",
  "humanReviewRequired": false,
  "reviewReason": null,
  "userMessage": ""
}

Return strict JSON only. Use null for unreadable fields. Do not invent data.`;

} else {
  // FRONT SIDE: Full verification — document type, name, DOB, expiry, side
  const prcFrontExtra = isPRC
    ? `\n\nPermanent Resident Card front-side specifics:\n- Extract the A-Number (Alien Registration Number, labeled "A#" or "A-Number", 9 digits after A). Return it in extractedFields.a_number.${knownANumber ? `\n- Known A-Number from profile: "${knownANumber}". If the card shows a different A-Number, set DOCUMENT_NUMBER_MISMATCH flag and canContinue=false with a clear message.` : ''}\n- Extract the card category (e.g. IR1, CR1, LB, RE-9, etc.) in extractedFields.category.`
    : '';

  prompt = `You are an identity-document verification assistant for a user guidance simulation.
Analyze the uploaded image of a physical US identity or work-authorization document.
Return strict JSON only. Do not include Markdown, prose, or code fences.

You must determine ALL of the following:
1. Is this a real supported US government ID or work authorization document?
2. What is the actual document type (even if user selected wrong)?
3. What is the actual side shown (front or back)?
4. Extract all visible text fields: first name, last name, middle name, DOB, expiration date, document number, address.
5. Compare extracted name to profile: legalFirstName="${p.legalFirstName || ''}" legalMiddleName="${p.legalMiddleName || ''}" legalLastName="${p.legalLastName || ''}".
6. Compare extracted DOB to profile: dateOfBirth="${p.dateOfBirth || ''}" (YYYY-MM-DD).
7. Check if the document is expired as of today.

App input:
requestId: ${d.requestId}
selectedDocumentType: ${d.selectedDocumentType}
documentSide: front${prcFrontExtra}

Rules:
- Only set NAME_MISMATCH when name is CLEARLY readable AND CLEARLY different from profile. If unreadable, use NOT_CHECKED.
- Only set DOB_MISMATCH when DOB is CLEARLY readable AND CLEARLY different. If unreadable, use NOT_CHECKED.
- Normalize all dates to YYYY-MM-DD.
- Two-digit years: DOB maps to past century, expiry maps to future.
- EXP/EXPIRES/4b EXPIRES/Card Expires = expiration date. ISS/ISSUED/4a ISSUED/Valid From = issue date NOT expiration.
- If back side submitted in front slot: SIDE_MISMATCH flag + REQUEST_FRONT_IMAGE.
- nextAction: CONTINUE (all pass, back image still needed → REQUEST_BACK_IMAGE), RETAKE_PHOTO (quality/no doc), REQUEST_FRONT_IMAGE (back in front slot), HALT_VERIFICATION (mismatch/expired/manipulation).
- canContinue=true only when: documentDetected=true, documentTypeMatchesSelection=true, sideMatchesSelection=true, nameMatchesProfile=true or NOT_CHECKED, dobMatchesProfile=true or NOT_CHECKED, documentExpired=false.
- If front is good and document requires a back side (drivers-license, state-id, permanent-resident-card, employment-authorization-card, military-id, passport-card): set nextAction=REQUEST_BACK_IMAGE and canContinue=true.

Supported document types: drivers-license, state-id, passport, passport-card, permanent-resident-card, employment-authorization-card, military-id, unknown.

Return exactly this JSON:
{
  "requestId": "${d.requestId}",
  "documentDetected": true,
  "userSelectedType": "${d.selectedDocumentType}",
  "userSelectedTypeLabel": "",
  "detectedDocumentType": "",
  "detectedDocumentTypeLabel": "",
  "documentTypeMatch": true,
  "detectedSide": "",
  "sideMatchesSelected": true,
  "extractedFields": {
    "first_name": null, "middle_name": null, "last_name": null, "full_name_raw": null,
    "date_of_birth": null, "expiration_date": null, "issue_date": null, "document_number": null,
    "address_line1": null, "city": null, "state": null, "zip": null, "sex": null,
    "card_number": null, "a_number": null, "category": null, "country_of_birth": null
  },
  "validationResults": {
    "nameMatch": { "status": "NOT_CHECKED", "details": null, "userProvided": "${(p.legalFirstName || '')} ${(p.legalLastName || '')}", "documentExtracted": null },
    "dobMatch": { "status": "NOT_CHECKED", "details": null, "userProvided": "${p.dateOfBirth || ''}", "documentExtracted": null },
    "addressMatch": { "status": "NOT_CHECKED", "details": null, "userProvided": null, "documentExtracted": null },
    "expirationStatus": "UNKNOWN",
    "photoIntegrity": "CLEAR"
  },
  "booleanChecks": {
    "documentDetected": true, "supportedDocumentType": true, "documentTypeMatchesSelection": true,
    "sideMatchesSelection": true, "frontImageRequired": false, "backImageRequired": false,
    "nameExtracted": true, "dobExtracted": true, "nameMatchesProfile": true, "dobMatchesProfile": true,
    "addressMatchesProfile": true, "documentExpired": false, "documentExpiresSoon": false,
    "imageQualityLow": false, "glareDetected": false, "croppedDocument": false,
    "physicalDocumentLikely": true, "digitalManipulationSuspected": false,
    "humanReviewRequired": false, "canContinue": true
  },
  "flags": [],
  "complianceEligibility": true,
  "nextAction": "CONTINUE",
  "humanReviewRequired": false,
  "reviewReason": null,
  "userMessage": ""
}

Return strict JSON only. Use null for unreadable fields. Do not invent data.`;
}

// Build Gemini request body
const geminiBody = {
  contents: [{
    parts: [
      { text: prompt },
      { inline_data: { mime_type: mimeType, data: base64Image } }
    ]
  }],
  generationConfig: { temperature: 0.1 }
};

return [{
  json: {
    ...d,
    googleDriveFileId: uploadNode.id || uploadNode.fileId || null,
    _geminiBody: geminiBody
  }
}];

const original = $('Build Gemini Request').item.json;
const response = $json;

// Extract text from every known Gemini response shape
function extractText(r) {
  if (r.candidates && Array.isArray(r.candidates) && r.candidates[0]) {
    const cand = r.candidates[0];
    const parts = cand.content && cand.content.parts;
    if (Array.isArray(parts) && parts[0] && typeof parts[0].text === 'string') return parts[0].text;
  }
  if (typeof r.text === 'string') return r.text;
  if (typeof r.content === 'string') return r.content;
  if (typeof r.output === 'string') return r.output;
  if (r.data && typeof r.data.text === 'string') return r.data.text;
  return '___PARSE_FAILED_KEYS:' + Object.keys(r).join(',') + '___SAMPLE:' + JSON.stringify(r).slice(0, 500);
}

function safeFailure(reason) {
  return {
    success: false,
    requestId: original.requestId,
    source: 'n8n-gemini-vision',
    googleDriveFileId: original.googleDriveFileId || null,
    userMessage: 'We could not verify this image automatically. Please try again or contact support.',
    nextAction: 'HALT_VERIFICATION',
    canContinue: false,
    humanReviewRequired: true,
    analysis: {
      requestId: original.requestId,
      documentDetected: false,
      booleanChecks: { canContinue: false, humanReviewRequired: true },
      flags: [{ severity: 'CRITICAL', code: 'MODEL_RESPONSE_INVALID', message: reason }],
      complianceEligibility: false,
      nextAction: 'HALT_VERIFICATION',
      humanReviewRequired: true,
      reviewReason: reason,
      userMessage: 'We could not verify this image automatically. Please try again or contact support.'
    }
  };
}

let raw = extractText(response).trim();
raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();

if (raw.startsWith('___PARSE_FAILED')) {
  return [{ json: safeFailure(raw) }];
}

let analysis;
try {
  analysis = JSON.parse(raw);
} catch (error) {
  return [{ json: safeFailure('JSON parse error: ' + error.message + ' | raw[:500]: ' + raw.slice(0, 500)) }];
}

const required = ['requestId','documentDetected','detectedDocumentType','detectedSide','booleanChecks','flags','nextAction','userMessage'];
const missing = required.filter(k => !(k in analysis));
if (missing.length) return [{ json: safeFailure('Missing required keys: ' + missing.join(', ')) }];

if (!analysis.requestId) analysis.requestId = original.requestId;

return [{ json: {
  success: true,
  requestId: original.requestId,
  source: 'n8n-gemini-vision',
  googleDriveFileId: original.googleDriveFileId || null,
  userMessage: analysis.userMessage || '',
  nextAction: analysis.nextAction || 'HALT_VERIFICATION',
  canContinue: Boolean(analysis.booleanChecks && analysis.booleanChecks.canContinue),
  humanReviewRequired: Boolean(analysis.humanReviewRequired || (analysis.booleanChecks && analysis.booleanChecks.humanReviewRequired)),
  analysis
} }];
